#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

const PARALLEL_JOBS = os.cpus().length;
const LOG_FILE = 'deployment.log';

function log(message) {
  const timestamp = new Date().toISOString();
  const logMessage = `[${timestamp}] ${message}\n`;
  fs.appendFileSync(LOG_FILE, logMessage);
  console.log(message);
}

function exec(command, options = {}) {
  try {
    log(`Executing: ${command}`);
    const result = execSync(command, {
      stdio: 'inherit',
      maxBuffer: 50 * 1024 * 1024,
      ...options
    });
    return result;
  } catch (error) {
    log(`Error executing command: ${command}`);
    throw error;
  }
}

function checkCache() {
  const lockFile = 'package-lock.json';
  const cacheFile = '.dep-cache';
  
  if (fs.existsSync(cacheFile) && fs.existsSync(lockFile)) {
    const cacheContent = fs.readFileSync(cacheFile, 'utf8');
    const lockContent = fs.readFileSync(lockFile, 'utf8');
    return cacheContent === lockContent;
  }
  return false;
}

function updateCache() {
  const lockFile = 'package-lock.json';
  const cacheFile = '.dep-cache';
  
  if (fs.existsSync(lockFile)) {
    fs.copyFileSync(lockFile, cacheFile);
  }
}

function installDependencies() {
  log('Step 1: Installing dependencies');
  
  if (checkCache()) {
    log('Dependencies cache is valid, skipping installation');
    return;
  }
  
  if (fs.existsSync('package-lock.json')) {
    exec('npm ci --prefer-offline --no-audit --progress=false');
  } else {
    exec('npm install --prefer-offline --no-audit --progress=false');
  }
  
  updateCache();
  log('Dependencies installed successfully');
}

function runTests() {
  log('Step 2: Running tests');
  
  const hasJest = fs.existsSync('jest.config.js') || fs.existsSync('jest.config.json');
  const hasMocha = fs.existsSync('test') || fs.existsSync('.mocharc.json');
  
  try {
    if (hasJest) {
      exec(`npm test -- --maxWorkers=${PARALLEL_JOBS} --bail --coverage=false`);
    } else if (hasMocha) {
      exec('npm test');
    } else {
      exec('npm test');
    }
    log('Tests passed successfully');
  } catch (error) {
    log('Tests failed');
    throw error;
  }
}

function buildApplication() {
  log('Step 3: Building application');
  
  const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf8'));
  
  if (packageJson.scripts && packageJson.scripts.build) {
    exec('npm run build');
  } else {
    log('No build script found, skipping build step');
  }
  
  log('Build completed successfully');
}

function deployProduction() {
  log('Step 4: Deploying to production');
  
  const deployMethod = process.env.DEPLOY_METHOD || 'pm2';
  const appName = process.env.APP_NAME || 'node-app';
  const port = process.env.PORT || 3000;
  
  if (deployMethod === 'pm2') {
    deployWithPM2(appName);
  } else if (deployMethod === 'docker') {
    deployWithDocker(appName);
  } else if (deployMethod === 'kubernetes') {
    deployWithKubernetes(appName);
  } else if (deployMethod === 'ssh') {
    deployWithSSH();
  } else if (deployMethod === 'systemd') {
    deployWithSystemd(appName);
  } else {
    log(`Unknown deployment method: ${deployMethod}`);
    throw new Error(`Unknown deployment method: ${deployMethod}`);
  }
  
  log('Deployment completed successfully');
}

function deployWithPM2(appName) {
  try {
    exec('pm2 --version', { stdio: 'pipe' });
  } catch (error) {
    log('PM2 not found, installing globally');
    exec('npm install -g pm2');
  }
  
  try {
    exec(`pm2 describe ${appName}`, { stdio: 'pipe' });
    exec(`pm2 reload ${appName} --update-env`);
    log(`PM2: Application ${appName} reloaded`);
  } catch (error) {
    const entryPoint = process.env.ENTRY_POINT || 'index.js';
    const instances = process.env.PM2_INSTANCES || PARALLEL_JOBS;
    exec(`pm2 start ${entryPoint} --name ${appName} -i ${instances}`);
    exec(`pm2 save`);
    log(`PM2: Application ${appName} started with ${instances} instances`);
  }
}

function deployWithDocker(appName) {
  const dockerImage = process.env.DOCKER_IMAGE || appName;
  const dockerTag = process.env.DOCKER_TAG || 'latest';
  const containerName = process.env.CONTAINER_NAME || appName;
  const port = process.env.PORT || 3000;
  
  log('Building Docker image');
  exec(`docker build -t ${dockerImage}:${dockerTag} .`);
  
  try {
    exec(`docker stop ${containerName}`, { stdio: 'pipe' });
    exec(`docker rm ${containerName}`, { stdio: 'pipe' });
  } catch (error) {
    log('No existing container to remove');
  }
  
  exec(`docker run -d --name ${containerName} -p ${port}:${port} --restart unless-stopped ${dockerImage}:${dockerTag}`);
  log(`Docker: Container ${containerName} deployed`);
  
  if (process.env.DOCKER_REGISTRY) {
    const registry = process.env.DOCKER_REGISTRY;
    exec(`docker tag ${dockerImage}:${dockerTag} ${registry}/${dockerImage}:${dockerTag}`);
    exec(`docker push ${registry}/${dockerImage}:${dockerTag}`);
    log(`Docker: Image pushed to ${registry}`);
  }
}

function deployWithKubernetes(appName) {
  const namespace = process.env.K8S_NAMESPACE || 'default';
  const deploymentFile = process.env.K8S_DEPLOYMENT_FILE || 'k8s-deployment.yaml';
  
  if (!fs.existsSync(deploymentFile)) {
    throw new Error(`Kubernetes deployment file not found: ${deploymentFile}`);
  }
  
  exec(`kubectl apply -f ${deploymentFile} -n ${namespace}`);
  exec(`kubectl rollout status deployment/${appName} -n ${namespace}`);
  log(`Kubernetes: Deployment ${appName} updated in namespace ${namespace}`);
}

function deployWithSSH() {
  const sshHost = process.env.SSH_HOST;
  const sshUser = process.env.SSH_USER || 'deploy';
  const deployPath = process.env.DEPLOY_PATH || '/var/www/app';
  const sshKey = process.env.SSH_KEY_PATH || '~/.ssh/id_rsa';
  
  if (!sshHost) {
    throw new Error('SSH_HOST environment variable is required for SSH deployment');
  }
  
  const distDir = process.env.DIST_DIR || 'dist';
  const excludeList = '--exclude=node_modules --exclude=.git --exclude=*.log';
  
  exec(`rsync -avz --delete ${excludeList} -e "ssh -i ${sshKey}" ./ ${sshUser}@${sshHost}:${deployPath}/`);
  
  const remoteCommands = [
    `cd ${deployPath}`,
    'npm ci --production --prefer-offline',
    'pm2 reload ecosystem.config.js || pm2 start ecosystem.config.js'
  ].join(' && ');
  
  exec(`ssh -i ${sshKey} ${sshUser}@${sshHost} "${remoteCommands}"`);
  log(`SSH: Deployed to ${sshHost}:${deployPath}`);
}

function deployWithSystemd(appName) {
  const serviceName = process.env.SYSTEMD_SERVICE || appName;
  
  exec(`sudo systemctl restart ${serviceName}`);
  exec(`sudo systemctl status ${serviceName}`);
  log(`Systemd: Service ${serviceName} restarted`);
}

function cleanup() {
  log('Step 5: Cleanup');
  
  const tmpDirs = ['tmp', '.cache', 'coverage'];
  tmpDirs.forEach(dir => {
    if (fs.existsSync(dir)) {
      fs.rmSync(dir, { recursive: true, force: true });
      log(`Removed ${dir}`);
    }
  });
}

function healthCheck() {
  log('Step 6: Health check');
  
  const healthUrl = process.env.HEALTH_CHECK_URL;
  if (!healthUrl) {
    log('No health check URL provided, skipping');
    return;
  }
  
  const maxRetries = parseInt(process.env.HEALTH_CHECK_RETRIES || '10');
  const retryDelay = parseInt(process.env.HEALTH_CHECK_DELAY || '3000');
  
  for (let i = 0; i < maxRetries; i++) {
    try {
      exec(`curl -f -s -o /dev/null -w "%{http_code}" ${healthUrl}`, { stdio: 'pipe' });
      log('Health check passed');
      return;
    } catch (error) {
      if (i < maxRetries - 1) {
        log(`Health check failed, retrying in ${retryDelay}ms... (${i + 1}/${maxRetries})`);
        execSync(`sleep ${retryDelay / 1000}`);
      }
    }
  }
  
  throw new Error('Health check failed after maximum retries');
}

function notifySlack(status, error = null) {
  const slackWebhook = process.env.SLACK_WEBHOOK_URL;
  if (!slackWebhook) return;
  
  const appName = process.env.APP_NAME || 'Application';
  const environment = process.env.ENVIRONMENT || 'production';
  const color = status === 'success' ? 'good' : 'danger';
  const message = status === 'success' 
    ? `${appName} deployed successfully to ${environment}`
    : `${appName} deployment failed in ${environment}: ${error?.message || 'Unknown error'}`;
  
  const payload = {
    attachments: [{
      color: color,
      text: message,
      footer: 'CI/CD Pipeline',
      ts: Math.floor(Date.now() / 1000)
    }]
  };
  
  try {
    exec(`curl -X POST -H 'Content-type: application/json' --data '${JSON.stringify(payload)}' ${slackWebhook}`, { stdio: 'pipe' });
  } catch (error) {
    log('Failed to send Slack notification');
  }
}

async function main() {
  const startTime = Date.now();
  log('=== CI/CD Pipeline Started ===');
  
  try {
    installDependencies();
    runTests();
    buildApplication();
    deployProduction();
    cleanup();
    healthCheck();
    
    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    log(`=== Pipeline Completed Successfully in ${duration}s ===`);
    notifySlack('success');
    process.exit(0);
  } catch (error) {
    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    log(`=== Pipeline Failed after ${duration}s ===`);
    log(`Error: ${error.message}`);
    notifySlack('failure', error);
    process.exit(1);
  }
}

if (require.main === module) {
  main();
}

module.exports = {
  installDependencies,
  runTests,
  buildApplication,
  deployProduction,
  cleanup,
  healthCheck
};